import '../lib/packet_decoder.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final cold = decodeSensorFrame([0x85, 0xff, 0x01]);
  final unavailable = decodeSensorFrame([0x00, 0x80, 0x01]);
  check(cold.rawTemperature == -123, 'near-zero negative raw sample');
  check(temperatureCelsius(cold) == -1.23, 'near-zero negative conversion');
  check(unavailable.rawTemperature == -32768, 'unavailable raw sentinel');
  check(
    temperatureCelsius(unavailable) == null,
    'unavailable sample remains distinct from negative temperature',
  );
}
